async def dispatch_tool(runtime, name: str, args: dict[str, Any]) -> str:
    """Execute a tool by name and return result string."""

    if name == "mara_connect":
        return await _handle_connect(runtime, args)

    if name == "mara_disconnect":
        return await _handle_disconnect(runtime, args)

    if name == "mara_get_state":
        return await _handle_get_state(runtime, args)

    if name == "mara_get_freshness":
        return await _handle_get_freshness(runtime, args)

    if name == "mara_get_events":
        return await _handle_get_events(runtime, args)

    if name == "mara_get_command_stats":
        return await _handle_get_command_stats(runtime, args)

    if name == "mara_wifi_status":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.wifi_service.status()
        runtime.record_command("wifi_status", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "wifi_status OK"
        return f"FAIL: {result.error}"

    if name == "mara_wifi_join":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.wifi_service.join(ssid=args["ssid"], password=args["password"], wait_for_connect=args.get("wait_for_connect", True), timeout_ms=args.get("timeout_ms", 10000))
        runtime.record_command("wifi_join", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "wifi_join OK"
        return f"FAIL: {result.error}"

    if name == "mara_wifi_disconnect":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.wifi_service.disconnect()
        runtime.record_command("wifi_disconnect", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "wifi_disconnect OK"
        return f"FAIL: {result.error}"

    if name == "mara_control_graph_upload":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.control_graph_service.upload(graph=args["graph"])
        runtime.record_command("control_graph_upload", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "control_graph_upload OK"
        return f"FAIL: {result.error}"

    if name == "mara_control_graph_apply":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.control_graph_service.apply(graph=args["graph"], enable=args.get("enable", True))
        runtime.record_command("control_graph_apply", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "control_graph_apply OK"
        return f"FAIL: {result.error}"

    if name == "mara_control_graph_status":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.control_graph_service.status()
        runtime.record_command("control_graph_status", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "control_graph_status OK"
        return f"FAIL: {result.error}"

    if name == "mara_control_graph_enable":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.control_graph_service.enable()
        runtime.record_command("control_graph_enable", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "control_graph_enable OK"
        return f"FAIL: {result.error}"

    if name == "mara_control_graph_disable":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.control_graph_service.disable()
        runtime.record_command("control_graph_disable", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "control_graph_disable OK"
        return f"FAIL: {result.error}"

    if name == "mara_control_graph_clear":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.control_graph_service.clear()
        runtime.record_command("control_graph_clear", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "control_graph_clear OK"
        return f"FAIL: {result.error}"

    if name == "mara_mcu_diagnostics_query":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.mcu_diagnostics_service.query()
        runtime.record_command("mcu_diagnostics_query", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "mcu_diagnostics_query OK"
        return f"FAIL: {result.error}"

    if name == "mara_mcu_diagnostics_reset":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.mcu_diagnostics_service.reset(clear_host_records=args.get("clear_host_records", False))
        runtime.record_command("mcu_diagnostics_reset", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return str(result.data) if result.data else "mcu_diagnostics_reset OK"
        return f"FAIL: {result.error}"

    if name == "mara_arm":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.arm()
        runtime.sync_state_result(result)
        runtime.record_command("arm", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Armed".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_disarm":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.disarm()
        runtime.sync_state_result(result)
        runtime.record_command("disarm", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Disarmed".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_stop":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.stop()
        runtime.sync_state_result(result)
        runtime.record_command("stop", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "Stopped".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_estop":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.estop()
        runtime.sync_state_result(result)
        runtime.record_command("estop", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "E-STOP activated".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_clear_estop":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.clear_estop()
        runtime.sync_state_result(result)
        runtime.record_command("clear_estop", args, result.ok, result.error, sent_at=sent_at)
        if result.ok:
            return "E-STOP cleared".format(**args)
        return f"FAIL: {result.error}"

    if name == "mara_activate":
        await runtime.ensure_connected()
        sent_at = datetime.now()
        result = await runtime.state_service.activate()
        runtime.sync_state_result(result)
